mapper.select:
select t.task_id, t.instance_id, t.node_id, t.approver_user_id, t.status, t.handled_time, p.process_name, i.business_type, i.business_id, i.business_title, n.node_name, concat(ifnull(starter.nick_name, starter.user_name), '（', starter.user_name, '）') as starter_user_name, concat(ifnull(approver.nick_name, approver.user_name), '（', approver.user_name, '）') as approver_user_name, t.create_by, t.create_time, t.update_by, t.update_time, t.remark from approval_task t left join approval_instance i on i.instance_id = t.instance_id left join approval_process p on p.process_id = i.process_id left join approval_node n on n.node_id = t.node_id left join sys_user starter on starter.user_id = i.starter_user_id left join sys_user approver on approver.user_id = t.approver_user_id
and t.instance_id = #{instanceId} and t.approver_user_id = #{approverUserId} and t.status = #{status}
order by t.task_id desc

mapper.update:
update approval_task
status = #{status}, handled_time = #{handledTime}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where task_id = #{taskId}

update approval_task
set status = #{status}, handled_time = sysdate(), update_by = #{updateBy}, update_time = sysdate()
where task_id = #{taskId}

update approval_task
set status = 'closed', update_by = #{updateBy}, update_time = sysdate()
where instance_id = #{instanceId}
  and node_id = #{nodeId}
  and task_id != #{excludeTaskId}
  and status = 'pending'
